#define MQ135_PIN A0
#define MQ135_DO  7
void setup() {
  Serial.begin(9600);
  pinMode(MQ135_DO, INPUT);
}
void loop() {
  int raw = analogRead(MQ135_PIN);
  int alert = digitalRead(MQ135_DO);
  Serial.print("Air Quality (raw): ");
  Serial.print(raw);
  Serial.print("  Alert: ");
  Serial.println(alert == LOW ? "GAS DETECTED!" : "Clean");
  delay(1000);
}
